import "./ColorItem.scss"

function ColorItem({color, inputType, checked, onCheked, onNonCheked}) {
    const changeColor = (e) => {
        if (e.currentTarget.checked) onCheked(color);
        else onNonCheked(color);
    }
    const checkedResult = checked(color);
    return (
        <label className="color p-2">
            <input 
                className="hidden"
                type={inputType}
                value={color}
                checked={checkedResult}
                onClick={changeColor}
            />
            <div className={"color-item br-2 bc-" + color} title={color}></div>
        </label>
    )
}
export default function ColorsContainer({style, inputType, checked, onCheked, onNonCheked}) {
    const colors = ["none", "blue", "purple", "pink", "red", "brown", "yellow", "green"];
    return (
        <div className="flex-row flex-wrap align-c" style={style}>
            {colors.map(color => (
                <ColorItem
                    key={"color-"+color}
                    inputType={inputType}
                    color={color}
                    checked={checked}
                    onCheked={onCheked}
                    onNonCheked={onNonCheked}
                />
            ))}
        </div>
    )
}
